using CertDesk.Models; using CertDesk.Services;
namespace CertDesk.Forms;
public sealed class TokenEditForm:Form
{ public TokenEditForm(Token e,TokenService service){Text="Токен"; StartPosition=FormStartPosition.CenterParent; Width=420; Height=620; var p=new FlowLayoutPanel{Dock=DockStyle.Fill,FlowDirection=FlowDirection.TopDown,Padding=new Padding(16)}; TextBox inv=Ui.TextBox(), type=Ui.TextBox(), model=Ui.TextBox(), serial=Ui.TextBox(), notes=Ui.TextBox(); ComboBox status=Ui.Combo(), holder=Ui.Combo(); DateTimePicker received=new(){Width=260}; status.Items.AddRange(["storage","issued","damaged","written_off"]); holder.DataSource=LookupService.Employees(); holder.ValueMember="id"; holder.DisplayMember="name"; inv.Text=e.InventoryNumber; type.Text=e.TokenType; model.Text=e.Model; serial.Text=e.SerialNumber; notes.Text=e.Notes; status.SelectedItem=e.Status; if(e.HolderId.HasValue) holder.SelectedValue=e.HolderId.Value; received.Value=e.ReceivedAt??DateTime.Today; foreach(Control c in [Ui.Label("Инвентарный номер"),inv,Ui.Label("Тип токена"),type,Ui.Label("Модель"),model,Ui.Label("Серийный номер"),serial,Ui.Label("Дата поступления"),received,Ui.Label("Статус"),status,Ui.Label("Текущий держатель"),holder,Ui.Label("Примечание"),notes]) p.Controls.Add(c); var save=Ui.Button("Сохранить"); p.Controls.Add(save); Controls.Add(p); save.Click+=(_,_)=>{try{e.InventoryNumber=inv.Text;e.TokenType=type.Text;e.Model=model.Text;e.SerialNumber=serial.Text;e.ReceivedAt=received.Value;e.Status=status.Text;e.HolderId=status.Text=="issued"?(int?)Convert.ToInt32(holder.SelectedValue):null;e.Notes=notes.Text;service.Save(e);DialogResult=DialogResult.OK;Close();}catch(Exception ex){Ui.Error(ex);}};}
}
